# Common Zod Patterns

Battle-tested patterns for real-world Zod usage.

## Environment Variable Validation

```typescript
import { z } from "zod";

const EnvSchema = z.object({
  NODE_ENV: z.enum(["development", "production", "test"]).default("development"),
  PORT: z.coerce.number().int().positive().default(3000),
  DATABASE_URL: z.string().url(),
  REDIS_URL: z.string().url().optional(),
  API_KEY: z.string().min(1),
  DEBUG: z.coerce.boolean().default(false),
  LOG_LEVEL: z.enum(["debug", "info", "warn", "error"]).default("info"),
  MAX_CONNECTIONS: z.coerce.number().int().positive().default(10),
});

// Parse and validate — fails fast with clear errors on missing/invalid vars
const env = EnvSchema.parse(process.env);

// Export typed env for the rest of the app
export type Env = z.infer<typeof EnvSchema>;
export default env;

// Usage:
// import env from "./env";
// env.PORT  — number, fully typed
// env.DATABASE_URL — string, guaranteed to be a valid URL
```

## API Request/Response Schemas

```typescript
// Request validation in Express
const CreateUserRequest = z.object({
  name: z.string().min(1).max(100),
  email: z.string().email(),
  password: z.string().min(8).max(128),
  role: z.enum(["user", "admin"]).default("user"),
});

// Response schema — normalize API responses
const ApiResponse = <T extends z.ZodTypeAny>(dataSchema: T) =>
  z.object({
    success: z.boolean(),
    data: dataSchema.optional(),
    error: z.object({
      code: z.string(),
      message: z.string(),
    }).optional(),
  });

// Validate external API responses
const GitHubUser = z.object({
  login: z.string(),
  id: z.number(),
  avatar_url: z.string().url(),
  html_url: z.string().url(),
  name: z.string().nullable(),
  bio: z.string().nullable(),
}).strip(); // ignore extra fields from API

async function fetchGitHubUser(username: string) {
  const res = await fetch(`https://api.github.com/users/${username}`);
  const json = await res.json();
  return GitHubUser.parse(json); // validated and typed
}
```

## Express/Fastify Middleware

```typescript
import { z, ZodSchema } from "zod";
import { Request, Response, NextFunction } from "express";

function validateBody<T extends ZodSchema>(schema: T) {
  return (req: Request, res: Response, next: NextFunction) => {
    const result = schema.safeParse(req.body);
    if (!result.success) {
      return res.status(400).json({
        error: "Validation failed",
        details: result.error.flatten(),
      });
    }
    req.body = result.data;
    next();
  };
}

// Usage
app.post("/users", validateBody(CreateUserRequest), (req, res) => {
  // req.body is validated CreateUserRequest
});
```

## Form Validation with React Hook Form

```typescript
import { z } from "zod";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";

const SignupSchema = z.object({
  email: z.string().email("Invalid email"),
  password: z.string().min(8, "Password must be at least 8 characters"),
  confirmPassword: z.string(),
}).refine((data) => data.password === data.confirmPassword, {
  message: "Passwords don't match",
  path: ["confirmPassword"],
});

type SignupForm = z.infer<typeof SignupSchema>;

function SignupPage() {
  const { register, handleSubmit, formState: { errors } } = useForm<SignupForm>({
    resolver: zodResolver(SignupSchema),
  });

  return (
    <form onSubmit={handleSubmit((data) => console.log(data))}>
      <input {...register("email")} />
      {errors.email && <span>{errors.email.message}</span>}
      <input type="password" {...register("password")} />
      {errors.password && <span>{errors.password.message}</span>}
      <input type="password" {...register("confirmPassword")} />
      {errors.confirmPassword && <span>{errors.confirmPassword.message}</span>}
      <button type="submit">Sign up</button>
    </form>
  );
}
```

## Discriminated Unions for Event Systems

```typescript
const WebhookEvent = z.discriminatedUnion("event", [
  z.object({
    event: z.literal("user.created"),
    data: z.object({ userId: z.string(), email: z.string().email() }),
  }),
  z.object({
    event: z.literal("user.deleted"),
    data: z.object({ userId: z.string(), reason: z.string().optional() }),
  }),
  z.object({
    event: z.literal("payment.completed"),
    data: z.object({ orderId: z.string(), amount: z.number(), currency: z.string() }),
  }),
]);

type WebhookEvent = z.infer<typeof WebhookEvent>;

function handleWebhook(payload: unknown) {
  const event = WebhookEvent.parse(payload);
  switch (event.event) {
    case "user.created":
      // event.data is { userId: string; email: string } — narrowed!
      break;
    case "payment.completed":
      // event.data is { orderId: string; amount: number; currency: string }
      break;
  }
}
```

## Recursive Types (Trees, JSON)

```typescript
// File system tree
interface FsNode {
  name: string;
  type: "file" | "directory";
  children?: FsNode[];
}

const FsNodeSchema: z.ZodType<FsNode> = z.object({
  name: z.string(),
  type: z.enum(["file", "directory"]),
  children: z.lazy(() => FsNodeSchema.array()).optional(),
});

// JSON value (self-referential)
type JsonValue = string | number | boolean | null | JsonValue[] | { [key: string]: JsonValue };

const JsonValueSchema: z.ZodType<JsonValue> = z.lazy(() =>
  z.union([
    z.string(),
    z.number(),
    z.boolean(),
    z.null(),
    z.array(JsonValueSchema),
    z.record(JsonValueSchema),
  ])
);
```

## tRPC Integration

```typescript
import { initTRPC } from "@trpc/server";
import { z } from "zod";

const t = initTRPC.create();

const appRouter = t.router({
  getUser: t.procedure
    .input(z.object({ id: z.string().uuid() }))
    .query(async ({ input }) => {
      // input is { id: string } — validated by Zod
      return db.users.findUnique({ where: { id: input.id } });
    }),

  createUser: t.procedure
    .input(CreateUserRequest)
    .mutation(async ({ input }) => {
      // input matches CreateUserRequest schema
      return db.users.create({ data: input });
    }),
});
```

## Config File Parsing

```typescript
const AppConfig = z.object({
  server: z.object({
    host: z.string().default("0.0.0.0"),
    port: z.number().int().positive().default(3000),
    cors: z.object({
      origins: z.array(z.string().url()).default(["http://localhost:3000"]),
      credentials: z.boolean().default(true),
    }).default({}),
  }).default({}),
  database: z.object({
    url: z.string().url(),
    pool: z.object({
      min: z.number().int().nonnegative().default(2),
      max: z.number().int().positive().default(10),
    }).default({}),
  }),
  features: z.object({
    darkMode: z.boolean().default(false),
    betaFeatures: z.boolean().default(false),
  }).default({}),
});

// Parse config file with full defaults
const config = AppConfig.parse(JSON.parse(fs.readFileSync("config.json", "utf8")));
```

## API Key / Secret Validation

```typescript
const ApiKey = z.string()
  .min(32, "API key too short")
  .regex(/^[a-zA-Z0-9_-]+$/, "Invalid API key format")
  .brand<"ApiKey">();

type ApiKey = z.infer<typeof ApiKey>;

// Functions that require a validated API key
function callApi(key: ApiKey, endpoint: string) { /* ... */ }

// Must parse first — prevents passing raw strings
const key = ApiKey.parse(process.env.API_KEY);
callApi(key, "/data"); // ✓
// callApi(process.env.API_KEY!, "/data"); // ✗ TypeScript error
```
